APP_TITLE = "RunningHub 图片生成工具"
SUPPORTED_EXTS = {".jpg", ".jpeg", ".png", ".webp", ".bmp"}
UPLOAD_URL = "https://www.runninghub.cn/openapi/v2/media/upload/binary"
SUBMIT_URL = "https://www.runninghub.cn/openapi/v2/rhart-image-n-pro/edit"
QUERY_URL = "https://www.runninghub.cn/openapi/v2/query"
REQUEST_TIMEOUT = 60
DEFAULT_POLL_INTERVAL_SECONDS = 5
DEFAULT_SUBMIT_WORKERS = 3

APP_ICON_PNG_BASE64 = ""


def get_app_dir() -> Path:
    if getattr(sys, "frozen", False):
        return Path(sys.executable).resolve().parent
    return Path(__file__).resolve().parent


APP_DIR = get_app_dir()
CONFIG_PATH = APP_DIR / "runninghub_gui_config.json"


def get_embedded_icon_png_bytes() -> bytes:
    return base64.b64decode(APP_ICON_PNG_BASE64.encode("ascii"))


def write_embedded_icon_ico(output_path: Path) -> Path:
    output_path = Path(output_path)
    output_path.parent.mkdir(parents=True, exist_ok=True)
    image = Image.open(io.BytesIO(get_embedded_icon_png_bytes())).convert("RGBA")
    sizes = [(256, 256), (128, 128), (64, 64), (48, 48), (32, 32), (16, 16)]
    image.save(output_path, format="ICO", sizes=sizes)
    return output_path


class RunningHubClient:
    def __init__(self, api_key: str):
        self.api_key = api_key.strip()
        self.session = requests.Session()
        self.session.headers.update({"Authorization": f"Bearer {self.api_key}"})

    def _json_headers(self) -> dict:
        return {
            "Authorization": f"Bearer {self.api_key}",
            "Content-Type": "application/json",
        }

    def upload_image(self, image_path: Path) -> str:
        with image_path.open("rb") as f:
            files = {"file": (image_path.name, f, "application/octet-stream")}
            response = self.session.post(UPLOAD_URL, files=files, timeout=REQUEST_TIMEOUT)
        self._raise_for_status(response, "上传图片失败")
        data = response.json()
        if data.get("code") != 0 or not data.get("data", {}).get("download_url"):
            raise RuntimeError(f"上传图片失败：{data}")
        return data["data"]["download_url"]

    def submit_task(self, image_urls: list[str], prompt: str, aspect_ratio: str, resolution: str) -> str:
        payload = {
            "imageUrls": image_urls,
            "prompt": prompt,
            "aspectRatio": aspect_ratio,
            "resolution": resolution,
        }
        response = self.session.post(
            SUBMIT_URL,
            headers=self._json_headers(),
            data=json.dumps(payload, ensure_ascii=False),
            timeout=REQUEST_TIMEOUT,
        )
        self._raise_for_status(response, "提交任务失败")
        data = response.json()
        task_id = data.get("taskId")
        if not task_id:
            raise RuntimeError(f"提交任务失败，未返回 taskId：{data}")
        return task_id

    def query_task(self, task_id: str) -> dict:
        payload = {"taskId": task_id}
        response = self.session.post(
            QUERY_URL,
            headers=self._json_headers(),
            data=json.dumps(payload, ensure_ascii=False),
            timeout=REQUEST_TIMEOUT,
        )
        self._raise_for_status(response, "查询任务失败")
        return response.json()

    @staticmethod
    def _raise_for_status(response: requests.Response, prefix: str) -> None:
        if response.status_code >= 400:
            text = response.text.strip()
            raise RuntimeError(f"{prefix}：HTTP {response.status_code} - {text}")


class SettingsDialog(tk.Toplevel):
    def __init__(self, master: "App") -> None:
        super().__init__(master)
        self.title("设置")
        self.transient(master)
        self.resizable(False, False)
        self.grab_set()

        self.master_app = master
        self.api_key_var = tk.StringVar(value=master.api_key_var.get())
        self.remember_var = tk.BooleanVar(value=master.remember_api_key_var.get())
        self.showing_plain_text = False

        self.columnconfigure(1, weight=1)

        ttk.Label(self, text="API Key").grid(row=0, column=0, sticky="w", padx=12, pady=(12, 8))
        self.api_key_entry = ttk.Entry(self, textvariable=self.api_key_var, show="*", width=48)
        self.api_key_entry.grid(row=0, column=1, sticky="ew", padx=(0, 8), pady=(12, 8))
        ttk.Button(self, text="显示", width=8, command=self._toggle_show).grid(
            row=0, column=2, sticky="e", padx=(0, 12), pady=(12, 8)
        )

        ttk.Checkbutton(
            self,
            text="记住 API Key（保存在 exe 同目录配置文件中）",
            variable=self.remember_var,
        ).grid(row=1, column=0, columnspan=3, sticky="w", padx=12, pady=(0, 8))

        ttk.Label(
            self,
            text="说明：主界面不显示 API Key。首次使用或更换 Key 时，在这里设置即可。",
            foreground="#666666",
        ).grid(row=2, column=0, columnspan=3, sticky="w", padx=12, pady=(0, 12))

        btns = ttk.Frame(self)
        btns.grid(row=3, column=0, columnspan=3, sticky="e", padx=12, pady=(0, 12))
        ttk.Button(btns, text="保存", command=self._save).pack(side="left", padx=(0, 8))
        ttk.Button(btns, text="取消", command=self.destroy).pack(side="left")

        self.bind("<Return>", lambda _e: self._save())
        self.bind("<Escape>", lambda _e: self.destroy())
        self.api_key_entry.focus_set()

        self.update_idletasks()
        self.geometry(f"+{master.winfo_rootx() + 120}+{master.winfo_rooty() + 120}")

    def _toggle_show(self) -> None:
        self.showing_plain_text = not self.showing_plain_text
        self.api_key_entry.configure(show="" if self.showing_plain_text else "*")

    def _save(self) -> None:
        api_key = self.api_key_var.get().strip()
        if not api_key:
            messagebox.showwarning(APP_TITLE, "请填写 API Key。", parent=self)
            return

        self.master_app.api_key_var.set(api_key)
        self.master_app.remember_api_key_var.set(bool(self.remember_var.get()))
        self.master_app.save_ui_config_only()
        self.master_app.refresh_settings_state_label()
        self.master_app.append_log("设置已保存。API Key 已更新到本地配置。")
        self.destroy()


