        self.title(APP_TITLE)
        self.geometry("1460x920")
        self.minsize(1220, 780)
        self._apply_app_icon()

        self.queue: queue.Queue = queue.Queue()
        self.stop_event = threading.Event()
        self.worker_thread: Optional[threading.Thread] = None
        self.file_rows: dict[str, str] = {}
        self.image_paths: list[Path] = []
        self.output_paths: dict[str, Optional[Path]] = {}
        self.preview_source_imgtk = None
        self.preview_result_imgtk = None
        self.window_icon_photo = None

        self.api_key_var = tk.StringVar()
        self.remember_api_key_var = tk.BooleanVar(value=False)
        self.input_folder_var = tk.StringVar()
        self.output_folder_var = tk.StringVar()
        self.aspect_ratio_var = tk.StringVar(value="3:4")
        self.resolution_var = tk.StringVar(value="1k")
        self.target_mb_var = tk.StringVar(value="0")
        self.submit_workers_var = tk.StringVar(value=str(DEFAULT_SUBMIT_WORKERS))
        self.poll_interval_var = tk.StringVar(value=str(DEFAULT_POLL_INTERVAL_SECONDS))
        self.concurrent_label_var = tk.StringVar(value="当前模式：先批量提交，再统一批量轮询")
        self.progress_var = tk.StringVar(value="未开始")
        self.settings_state_var = tk.StringVar(value="API Key：未设置")

